const HEADER_FILL = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF2D3250' } };
const ALT_FILL    = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFF7F7F7' } };

/**
 * Generate a factory offer template xlsx buffer.
 *
 * @param {string} vendorName - Display name pre-filled into the metadata banner.
 * @param {Array<{id: number, name: string}>} customers - For the Customer dropdown.
 * @returns {Promise<Buffer>}
 */
exports.generateTemplate = async (vendorName, customers) => {
  const workbook = new ExcelJS.Workbook();
  workbook.creator = 'DesignFlow PLM';
  workbook.created = new Date();

  // ── Hidden lookup sheet (Customer list for data validation) ──────────────
  const lookupsSheet = workbook.addWorksheet('Lookups');
  lookupsSheet.state = 'hidden';
  customers.forEach((c, i) => {
    lookupsSheet.getCell(i + 1, 1).value = c.name;
  });

  // ── Main offer sheet ─────────────────────────────────────────────────────
  const ws = workbook.addWorksheet('Offer Template');

  // Row 1 — metadata banner
  const metaRow = ws.getRow(1);
  metaRow.getCell(1).value = `Factory: ${vendorName}`;
  metaRow.getCell(1).font = { bold: true, size: 12 };
  const dateStr = new Date().toLocaleDateString('en-US', {
    year: 'numeric', month: 'long', day: 'numeric'
  });
  metaRow.getCell(4).value = `Date: ${dateStr}`;
  metaRow.getCell(4).font = { italic: true, color: { argb: 'FF555555' } };
  metaRow.height = 24;
  // Light banner fill across first row
  for (let c = 1; c <= COLUMNS.length; c++) {
    metaRow.getCell(c).fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFE8ECF4' } };
  }

  // Row 2 — column headers
  const headerRow = ws.getRow(HEADER_ROW);
  COLUMNS.forEach((col, idx) => {
    const cell = headerRow.getCell(idx + 1);
    cell.value = col.header;
    cell.font = { bold: true, color: { argb: 'FFFFFFFF' }, size: 10 };
    cell.fill = HEADER_FILL;
    cell.alignment = { vertical: 'middle', horizontal: 'center', wrapText: true };
    cell.border = {
      bottom: { style: 'medium', color: { argb: 'FF1A2040' } }
    };
    ws.getColumn(idx + 1).width = col.width;
  });
  headerRow.height = 32;

  // Rows 3–52 — data input rows
  for (let r = DATA_ROW_START; r < DATA_ROW_START + DATA_ROWS; r++) {
    const row = ws.getRow(r);
    row.height = 64; // tall so factories can embed images

    // Alternating row shading (skip image column styling)
    if (r % 2 === 0) {
      for (let c = 1; c <= COLUMNS.length; c++) {
        if (c !== IMAGE_COL) {
          row.getCell(c).fill = ALT_FILL;
        }
      }
    }

    // Customer dropdown (data validation references hidden Lookups sheet)
    row.getCell(CUSTOMER_COL).dataValidation = {
      type: 'list',
      allowBlank: true,
      showErrorMessage: true,
      errorTitle: 'Invalid Customer',
      error: 'Please select a customer from the dropdown list.',
      formulae: [`Lookups!$A$1:$A$${Math.max(customers.length, 1)}`],
    };

    // Price Terms dropdown
    row.getCell(TERMS_COL).dataValidation = {
      type: 'list',
      allowBlank: true,
      formulae: [`"${PRICE_TERMS.join(',')}"`],
    };

    // Light hint style on image column
    const imgCell = row.getCell(IMAGE_COL);
    imgCell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFFFF8E1' } };
    imgCell.alignment = { vertical: 'middle', horizontal: 'center' };
  }

  // Freeze the first two rows so headers are always visible while scrolling
  ws.views = [
    { state: 'frozen', xSplit: 0, ySplit: 2, topLeftCell: 'A3', activeCell: 'A3' }
  ];

  // ── Instructions sheet ───────────────────────────────────────────────────
  const instrSheet = workbook.addWorksheet('Instructions');
  instrSheet.getColumn(1).width = 82;

  const lines = [
    ['FACTORY OFFER TEMPLATE — HOW TO FILL IN', true],
    [''],
    ['1. One row = one product offer. Fill in as many rows as needed (up to 50 in this template).'],
    ['2. DESCRIPTION — Enter a clear product description (material, design, finish, color, etc.)'],
    ['3. CUSTOMER — Select from the dropdown. If your customer is not listed, leave blank and add a note.'],
    ['4. QUANTITY — Minimum order quantity for the quoted price.'],
    ['5. CASE PACK — Number of units per export carton.'],
    ['6. QUOTE PRICE — Your offered price in USD.'],
    ['7. PRICE TERMS — Select from dropdown (FOB, CIF, EXW, DDP, POE).'],
    ['8. CARTON DIMENSIONS — Length × Width × Height in centimeters for a single carton.'],
    ['9. LEAD TIME — Estimated production + delivery lead time in days.'],
    ['10. FOB COUNTRY / FOB PORT — Origin country and loading port.'],
    ['11. NOTES — Any conditions, MOQ notes, or product-specific comments.'],
    [''],
    ['HOW TO INSERT A PRODUCT IMAGE:', true],
    [''],
    ['  Excel (Windows/Mac):'],
    ['    • Click on the yellow "Image" cell in your product row.'],
    ['    • Go to:  Insert → Pictures → Place in Cell'],
    ['    • Browse to the image file and insert it.'],
    ['    • One image per row only. The image should fit inside the yellow cell.'],
    [''],
    ['  If "Place in Cell" is not available in your Excel version:'],
    ['    • Insert the image anywhere on the sheet and manually position it over the image cell.'],
    ['    • The system will still attempt to extract it.'],
    [''],
    ['When you have finished filling in all rows and inserting images:'],
    ['  • Save the file (keep .xlsx format).'],
    ['  • Go back to the portal and use the "Upload Offers" button to submit this file.'],
  ];

